class CookieStore(typing.MutableMapping[str, str]):
    """A deterministic, modern HTTP cookie store."""

    def __init__(
        self,
        cookies: CookieTypes | None = None,
        *,
        max_cookies: int | None = None,
        max_cookies_per_domain: int | None = None,
    ) -> None:
        for value, name in (
            (max_cookies, "max_cookies"),
            (max_cookies_per_domain, "max_cookies_per_domain"),
        ):
            if value is not None and (
                not isinstance(value, int) or isinstance(value, bool)
            ):
                raise TypeError(f"{name} must be an int or None")
            if value is not None and value < 0:
                raise ValueError(f"{name} must be greater than or equal to zero")
        self.max_cookies = max_cookies
        self.max_cookies_per_domain = max_cookies_per_domain
        self._cookies: list[_StoredCookie] = []
        self._creation = 0
        if cookies is not None:
            self.update(cookies)

    @staticmethod
    def _domain_matches(host: str, domain: str) -> bool:
        host, domain = host.lower(), domain.lower().lstrip(".")
        return host == domain or host.endswith("." + domain)

    @staticmethod
    def _default_path(path: str) -> str:
        if not path.startswith("/") or path.count("/") <= 1:
            return "/"
        return path.rsplit("/", 1)[0] or "/"

    @staticmethod
    def _path_matches(request_path: str, path: str) -> bool:
        return request_path == path or (
            request_path.startswith(path)
            and (path.endswith("/") or request_path[len(path) :].startswith("/"))
        )

    def _remove_key(self, name: str, domain: str, path: str) -> None:
        self._cookies[:] = [
            c
            for c in self._cookies
            if (c.name, c.domain, c.path) != (name, domain, path)
        ]

    def _store(self, cookie: _StoredCookie) -> None:
        self._remove_key(cookie.name, cookie.domain, cookie.path)
        self._cookies.append(cookie)
        self._evict()

    def _purge_expired(self) -> None:
        now = datetime.datetime.now(datetime.timezone.utc).timestamp()
        self._cookies[:] = [
            c for c in self._cookies if c.expires is None or c.expires > now
        ]

    def _evict(self) -> None:
        if self.max_cookies_per_domain is not None:
            for domain in {c.domain for c in self._cookies}:
                matching = sorted(
                    (c for c in self._cookies if c.domain == domain),
                    key=lambda c: c.creation,
                )
                while len(matching) > self.max_cookies_per_domain:
                    victim = matching.pop(0)
                    self._cookies.remove(victim)
        if self.max_cookies is not None:
            while len(self._cookies) > self.max_cookies:
                self._cookies.remove(min(self._cookies, key=lambda c: c.creation))

